// ---- DAO, Entities, and CRUD ----

// ---- Entity with relationships ----
@Entity(tableName = "users")
data class UserEntity(
    @PrimaryKey
    val id: Int,
    val name: String,
    val email: String
)

@Entity(tableName = "posts")
data class PostEntity(
    @PrimaryKey(autoGenerate = true)
    val id: Int = 0,
    val userId: Int,
    val title: String,
    val body: String,
    val createdAt: Long = System.currentTimeMillis()
)

// ---- Embedded entity ----
class Address(
    val street: String,
    val city: String,
    val zipCode: String
)

// ---- Type converter for embedded objects ----
class Converters {
    @TypeConverter
    fun fromAddress(address: Address): String {
        return "${address.street},${address.city},${address.zipCode}"
    }

    @TypeConverter
    fun toAddress(data: String): Address {
        val parts = data.split(",")
        return Address(parts[0], parts[1], parts[2])
    }
}

// ---- Complete DAO ----
@Dao
interface PostDao {
    // ---- Create ----
    @Insert
    suspend fun insertPost(post: PostEntity): Long

    @Insert
    suspend fun insertMultiple(posts: List<PostEntity>): List<Long>

    // ---- Read ----
    @Query("SELECT * FROM posts ORDER BY id DESC")
    fun getAllPosts(): Flow<List<PostEntity>>

    @Query("SELECT * FROM posts WHERE userId = :userId")
    fun getPostsByUser(userId: Int): Flow<List<PostEntity>>

    @Query("SELECT * FROM posts WHERE id = :id")
    suspend fun getPostById(id: Int): PostEntity?

    @Query("SELECT COUNT(*) FROM posts")
    suspend fun getPostCount(): Int

    @Query("SELECT * FROM posts WHERE title LIKE '%' || :query || '%'")
    fun searchPosts(query: String): Flow<List<PostEntity>>

    // ---- Update ----
    @Update
    suspend fun updatePost(post: PostEntity)

    @Query("UPDATE posts SET title = :title, body = :body WHERE id = :id")
    suspend fun updatePostContent(id: Int, title: String, body: String)

    // ---- Delete ----
    @Delete
    suspend fun deletePost(post: PostEntity)

    @Query("DELETE FROM posts WHERE id = :id")
    suspend fun deletePostById(id: Int)

    @Query("DELETE FROM posts WHERE userId = :userId")
    suspend fun deletePostsByUser(userId: Int)

    @Query("DELETE FROM posts")
    suspend fun deleteAllPosts()
}

// ---- Complete Repository ----
class CompletePostRepository(private val dao: PostDao) {
    fun getAllPosts(): Flow<List<PostEntity>> = dao.getAllPosts()

    fun getPostsByUser(userId: Int): Flow<List<PostEntity>> = dao.getPostsByUser(userId)

    fun searchPosts(query: String): Flow<List<PostEntity>> = dao.searchPosts(query)

    suspend fun getPostById(id: Int): PostEntity? = dao.getPostById(id)

    suspend fun getPostCount(): Int = dao.getPostCount()

    suspend fun createPost(userId: Int, title: String, body: String): Long {
        val post = PostEntity(
            userId = userId,
            title = title,
            body = body
        )
        return dao.insertPost(post)
    }

    suspend fun updatePost(post: PostEntity) = dao.updatePost(post)

    suspend fun updatePostContent(id: Int, title: String, body: String) =
        dao.updatePostContent(id, title, body)

    suspend fun deletePost(post: PostEntity) = dao.deletePost(post)

    suspend fun deletePostById(id: Int) = dao.deletePostById(id)

    suspend fun deletePostsByUser(userId: Int) = dao.deletePostsByUser(userId)

    suspend fun deleteAllPosts() = dao.deleteAllPosts()
}

// ---- ViewModel with CRUD ----
class CompletePostViewModel(private val repository: CompletePostRepository) : ViewModel() {
    val allPosts = repository.getAllPosts()
        .stateIn(
            scope = viewModelScope,
            started = SharingStarted.WhileSubscribed(),
            initialValue = emptyList()
        )

    private val _selectedPost = MutableStateFlow<PostEntity?>(null)
    val selectedPost: StateFlow<PostEntity?> = _selectedPost.asStateFlow()

    private val _isLoading = MutableStateFlow(false)
    val isLoading: StateFlow<Boolean> = _isLoading.asStateFlow()

    private val _error = MutableStateFlow<String?>(null)
    val error: StateFlow<String?> = _error.asStateFlow()

    private val _searchResults = MutableStateFlow<List<PostEntity>>(emptyList())
    val searchResults: StateFlow<List<PostEntity>> = _searchResults.asStateFlow()

    // ---- Create ----
    fun createPost(userId: Int, title: String, body: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                repository.createPost(userId, title, body)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to create post: ${e.message}"
            } finally {
                _isLoading.value = false
            }
        }
    }

    // ---- Read ----
    fun selectPost(id: Int) {
        viewModelScope.launch {
            try {
                _selectedPost.value = repository.getPostById(id)
            } catch (e: Exception) {
                _error.value = "Failed to load post: ${e.message}"
            }
        }
    }

    fun searchPosts(query: String) {
        viewModelScope.launch {
            try {
                repository.searchPosts(query).collect { results ->
                    _searchResults.value = results
                }
            } catch (e: Exception) {
                _error.value = "Search failed: ${e.message}"
            }
        }
    }

    // ---- Update ----
    fun updatePost(id: Int, title: String, body: String) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                repository.updatePostContent(id, title, body)
                // Refresh selected post
                _selectedPost.value = repository.getPostById(id)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to update post: ${e.message}"
            } finally {
                _isLoading.value = false
            }
        }
    }

    // ---- Delete ----
    fun deletePost(id: Int) {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                repository.deletePostById(id)
                if (_selectedPost.value?.id == id) {
                    _selectedPost.value = null
                }
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to delete post: ${e.message}"
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun deleteAllPosts() {
        viewModelScope.launch {
            _isLoading.value = true
            try {
                repository.deleteAllPosts()
                _selectedPost.value = null
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to delete all: ${e.message}"
            } finally {
                _isLoading.value = false
            }
        }
    }

    fun clearError() {
        _error.value = null
    }
}

// ---- UI ----
@Composable
fun CompletePostScreen() {
    val context = LocalContext.current
    val db = remember { AppDatabase.getInstance(context) }
    val repository = remember { CompletePostRepository(db.postDao()) }
    val viewModel: CompletePostViewModel = viewModel(factory = CompletePostViewModelFactory(repository))

    val posts by viewModel.allPosts.collectAsState()
    val selectedPost by viewModel.selectedPost.collectAsState()
    val isLoading by viewModel.isLoading.collectAsState()
    val error by viewModel.error.collectAsState()

    var title by remember { mutableStateOf("") }
    var body by remember { mutableStateOf("") }
    var searchQuery by remember { mutableStateOf("") }

    Scaffold(
        topBar = { TopAppBar { Text("CRUD Operations") } }
    ) { paddingValues ->
        Column(
            modifier = Modifier
                .fillMaxSize()
                .padding(paddingValues)
                .padding(16.dp),
            verticalArrangement = Arrangement.spacedBy(8.dp)
        ) {
            if (isLoading) {
                Box(modifier = Modifier.fillMaxWidth().height(50.dp), contentAlignment = Alignment.Center) {
                    CircularProgressIndicator()
                }
            }

            if (error != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    colors = CardDefaults.cardColors(
                        containerColor = MaterialTheme.colorScheme.errorContainer
                    )
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text(error ?: "", color = MaterialTheme.colorScheme.onErrorContainer)
                        Button(onClick = { viewModel.clearError() }) { Text("Dismiss") }
                    }
                }
            }

            // ---- Selected post ----
            if (selectedPost != null) {
                Card(
                    modifier = Modifier.fillMaxWidth(),
                    elevation = CardDefaults.cardElevation(4.dp)
                ) {
                    Column(modifier = Modifier.padding(16.dp)) {
                        Text("Selected Post:", style = MaterialTheme.typography.titleMedium)
                        Text(selectedPost?.title ?: "", style = MaterialTheme.typography.titleLarge)
                        Text(selectedPost?.body ?: "")
                        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                            Button(
                                onClick = { selectedPost?.let { viewModel.deletePost(it.id) } },
                                modifier = Modifier.weight(1f),
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = MaterialTheme.colorScheme.error
                                )
                            ) { Text("Delete Selected") }
                        }
                    }
                }
            }

            // ---- Create form ----
            Text("Create Post", style = MaterialTheme.typography.titleMedium)
            OutlinedTextField(value = title, onValueChange = { title = it }, label = { Text("Title") })
            OutlinedTextField(value = body, onValueChange = { body = it }, label = { Text("Body") })
            Button(
                onClick = {
                    if (title.isNotBlank() && body.isNotBlank()) {
                        viewModel.createPost(1, title, body)
                        title = ""; body = ""
                    }
                },
                modifier = Modifier.fillMaxWidth()
            ) { Text("Create Post") }

            // ---- Search ----
            OutlinedTextField(
                value = searchQuery,
                onValueChange = { searchQuery = it; viewModel.searchPosts(it) },
                label = { Text("Search Posts") },
                modifier = Modifier.fillMaxWidth()
            )

            // ---- Posts list ----
            LazyColumn(verticalArrangement = Arrangement.spacedBy(4.dp)) {
                val displayPosts = if (searchQuery.isNotBlank()) viewModel.searchResults.value else posts
                items(displayPosts) { post ->
                    Card(
                        modifier = Modifier
                            .fillMaxWidth()
                            .clickable { viewModel.selectPost(post.id) },
                        elevation = CardDefaults.cardElevation(2.dp)
                    ) {
                        Column(modifier = Modifier.padding(8.dp)) {
                            Text(post.title, style = MaterialTheme.typography.titleMedium)
                            Text(post.body, style = MaterialTheme.typography.bodyMedium, maxLines = 2)
                            Text("ID: ${post.id}, User: ${post.userId}", style = MaterialTheme.typography.bodySmall)
                        }
                    }
                }
            }

            // ---- Danger buttons ----
            Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
                Button(
                    onClick = { viewModel.deleteAllPosts() },
                    modifier = Modifier.weight(1f),
                    colors = ButtonDefaults.buttonColors(
                        containerColor = MaterialTheme.colorScheme.error
                    )
                ) { Text("Delete All") }
            }
        }
    }
}

class CompletePostViewModelFactory(private val repository: CompletePostRepository) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(CompletePostViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return CompletePostViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

