package com.example.crud

import android.content.Context
import androidx.compose.foundation.layout.*
import androidx.compose.foundation.lazy.LazyColumn
import androidx.compose.foundation.lazy.items
import androidx.compose.material3.*
import androidx.compose.runtime.*
import androidx.compose.ui.Alignment
import androidx.compose.ui.Modifier
import androidx.compose.ui.platform.LocalContext
import androidx.compose.ui.unit.dp
import androidx.lifecycle.ViewModel
import androidx.lifecycle.ViewModelProvider
import androidx.lifecycle.compose.viewModel
import androidx.room.*
import kotlinx.coroutines.flow.Flow
import kotlinx.coroutines.flow.MutableStateFlow
import kotlinx.coroutines.flow.StateFlow
import kotlinx.coroutines.flow.asStateFlow
import kotlinx.coroutines.flow.stateIn
import kotlinx.coroutines.launch

@Entity(tableName = "items")
data class Item(
    @PrimaryKey(autoGenerate = true)
    val id: Int = 0,
    val name: String,
    val quantity: Int
)

@Dao
interface ItemDao {
    @Insert
    suspend fun insert(item: Item)

    @Query("SELECT * FROM items ORDER BY id DESC")
    fun getAll(): Flow<List<Item>>

    @Update
    suspend fun update(item: Item)

    @Delete
    suspend fun delete(item: Item)
}

@Database(entities = [Item::class], version = 1)
abstract class AppDatabase : RoomDatabase() {
    abstract fun itemDao(): ItemDao

    companion object {
        @Volatile
        private var INSTANCE: AppDatabase? = null

        fun getInstance(context: Context): AppDatabase {
            return INSTANCE ?: synchronized(this) {
                val instance = Room.databaseBuilder(
                    context.applicationContext,
                    AppDatabase::class.java,
                    "items_db"
                ).build()
                INSTANCE = instance
                instance
            }
        }
    }
}

class ItemRepository(private val dao: ItemDao) {
    fun getAll(): Flow<List<Item>> = dao.getAll()
    suspend fun insert(item: Item) = dao.insert(item)
    suspend fun update(item: Item) = dao.update(item)
    suspend fun delete(item: Item) = dao.delete(item)
}

class ItemViewModel(private val repository: ItemRepository) : ViewModel() {
    val items = repository.getAll().stateIn(
        scope = viewModelScope,
        started = SharingStarted.WhileSubscribed(),
        initialValue = emptyList()
    )

    private val _error = MutableStateFlow<String?>(null)
    val error: StateFlow<String?> = _error.asStateFlow()

    fun addItem(name: String, quantity: Int) {
        viewModelScope.launch {
            try {
                repository.insert(Item(name = name, quantity = quantity))
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to add item: ${e.message}"
            }
        }
    }

    fun updateItem(item: Item) {
        viewModelScope.launch {
            try {
                repository.update(item)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to update item: ${e.message}"
            }
        }
    }

    fun deleteItem(item: Item) {
        viewModelScope.launch {
            try {
                repository.delete(item)
                _error.value = null
            } catch (e: Exception) {
                _error.value = "Failed to delete item: ${e.message}"
            }
        }
    }

    fun clearError() {
        _error.value = null
    }
}

class ItemViewModelFactory(private val repository: ItemRepository) : ViewModelProvider.Factory {
    override fun <T : ViewModel> create(modelClass: Class<T>): T {
        if (modelClass.isAssignableFrom(ItemViewModel::class.java)) {
            @Suppress("UNCHECKED_CAST")
            return ItemViewModel(repository) as T
        }
        throw IllegalArgumentException("Unknown ViewModel class")
    }
}

@Composable
fun CrudApp() {
    val context = LocalContext.current
    val db = remember { AppDatabase.getInstance(context) }
    val repository = remember { ItemRepository(db.itemDao()) }
    val viewModel: ItemViewModel = viewModel(factory = ItemViewModelFactory(repository))

    val items by viewModel.items.collectAsState()
    val error by viewModel.error.collectAsState()

    var name by remember { mutableStateOf("") }
    var quantity by remember { mutableStateOf("") }

    Column(
        modifier = Modifier.fillMaxSize().padding(16.dp),
        verticalArrangement = Arrangement.spacedBy(8.dp)
    ) {
        if (error != null) {
            Card(
                modifier = Modifier.fillMaxWidth(),
                colors = CardDefaults.cardColors(
                    containerColor = MaterialTheme.colorScheme.errorContainer
                )
            ) {
                Column(modifier = Modifier.padding(16.dp)) {
                    Text(error ?: "", color = MaterialTheme.colorScheme.onErrorContainer)
                    Button(onClick = { viewModel.clearError() }) { Text("Dismiss") }
                }
            }
        }

        Row(modifier = Modifier.fillMaxWidth(), horizontalArrangement = Arrangement.spacedBy(8.dp)) {
            OutlinedTextField(
                value = name,
                onValueChange = { name = it },
                label = { Text("Name") },
                modifier = Modifier.weight(2f)
            )
            OutlinedTextField(
                value = quantity,
                onValueChange = { quantity = it },
                label = { Text("Qty") },
                modifier = Modifier.weight(1f),
                keyboardOptions = KeyboardOptions(keyboardType = KeyboardType.Number)
            )
            Button(
                onClick = {
                    if (name.isNotBlank()) {
                        viewModel.addItem(name, quantity.toIntOrNull() ?: 0)
                        name = ""; quantity = ""
                    }
                }
            ) { Text("Add") }
        }

        LazyColumn(verticalArrangement = Arrangement.spacedBy(4.dp)) {
            items(items) { item ->
                Card(modifier = Modifier.fillMaxWidth(), elevation = CardDefaults.cardElevation(2.dp)) {
                    Row(
                        modifier = Modifier.fillMaxWidth().padding(8.dp),
                        horizontalArrangement = Arrangement.SpaceBetween,
                        verticalAlignment = Alignment.CenterVertically
                    ) {
                        Column {
                            Text(item.name, style = MaterialTheme.typography.titleMedium)
                            Text("Quantity: ${item.quantity}", style = MaterialTheme.typography.bodyMedium)
                        }
                        Row(horizontalArrangement = Arrangement.spacedBy(4.dp)) {
                            Button(
                                onClick = {
                                    val newQty = (item.quantity + 1).coerceAtMost(100)
                                    viewModel.updateItem(item.copy(quantity = newQty))
                                }
                            ) { Text("+") }
                            Button(
                                onClick = {
                                    val newQty = (item.quantity - 1).coerceAtLeast(0)
                                    if (newQty == 0) viewModel.deleteItem(item)
                                    else viewModel.updateItem(item.copy(quantity = newQty))
                                }
                            ) { Text("-") }
                            Button(
                                onClick = { viewModel.deleteItem(item) },
                                colors = ButtonDefaults.buttonColors(
                                    containerColor = MaterialTheme.colorScheme.error
                                )
                            ) { Text("Delete") }
                        }
                    }
                }
            }
        }
    }
}
